import requests

BASE_URL = "http://localhost:3001"
LOGIN_ENDPOINT = "/api/auth/login"
TIMEOUT = 30

def test_post_apiauthlogin_with_valid_and_invalid_credentials():
    url = BASE_URL + LOGIN_ENDPOINT
    headers = {"Content-Type": "application/json"}

    # Valid credentials payload
    valid_payload = {
        "email": "admin@example.com",
        "password": "admin123"
    }
    # Invalid credentials payload
    invalid_payload = {
        "email": "admin@example.com",
        "password": "wrongpassword"
    }

    # Test login with valid credentials
    try:
        valid_response = requests.post(url, json=valid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request to {url} with valid credentials failed: {e}"
    assert valid_response.status_code == 200, f"Expected 200 OK for valid credentials but got {valid_response.status_code}"
    try:
        json_data = valid_response.json()
    except ValueError:
        assert False, "Response for valid credentials is not valid JSON"
    assert "token" in json_data and isinstance(json_data["token"], str) and len(json_data["token"].strip()) > 0, "Valid login response missing JWT token"

    # Test login with invalid credentials
    try:
        invalid_response = requests.post(url, json=invalid_payload, headers=headers, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Request to {url} with invalid credentials failed: {e}"
    assert invalid_response.status_code == 401, f"Expected 401 Unauthorized for invalid credentials but got {invalid_response.status_code}"
    try:
        json_data = invalid_response.json()
    except ValueError:
        assert False, "Response for invalid credentials is not valid JSON"
    # Validate error message field containing 'Invalid credentials'
    error_message = None
    if isinstance(json_data, dict):
        error_message = json_data.get("error") or json_data.get("message") or json_data.get("detail")
    assert error_message is not None, "Error message missing in invalid credentials response"
    assert "invalid credentials" in error_message.lower(), f"Expected error message to contain 'Invalid credentials' but got: {error_message}"

test_post_apiauthlogin_with_valid_and_invalid_credentials()

import requests

BASE_URL = "http://localhost:3001"
LOGIN_ENDPOINT = f"{BASE_URL}/api/auth/login"
DASHBOARD_ENDPOINT = f"{BASE_URL}/api/dashboard"

ADMIN_EMAIL = "admin@example.com"
ADMIN_PASSWORD = "admin123"


def test_tc004_get_api_dashboard_with_and_without_authorization():
    # Get JWT token by logging in as admin
    login_payload = {"email": ADMIN_EMAIL, "password": ADMIN_PASSWORD}
    try:
        login_resp = requests.post(
            LOGIN_ENDPOINT, json=login_payload, timeout=30
        )
        login_resp.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Login request failed: {e}"

    login_data = login_resp.json()
    assert "token" in login_data, "Login response missing token"
    token = login_data["token"]
    assert isinstance(token, str) and len(token) > 0, "Invalid token received"

    headers_auth = {"Authorization": f"Bearer {token}"}

    # Call /api/dashboard with valid Authorization header
    try:
        dashboard_auth_resp = requests.get(
            DASHBOARD_ENDPOINT, headers=headers_auth, timeout=30
        )
        dashboard_auth_resp.raise_for_status()
    except requests.RequestException as e:
        assert False, f"Authorized dashboard request failed: {e}"

    assert dashboard_auth_resp.status_code == 200, "Expected HTTP 200 for authorized request"
    dashboard_data = dashboard_auth_resp.json()
    # Validate keys in dashboard response
    expected_keys = {"revenue", "router_status", "active_users"}
    missing_keys = expected_keys - dashboard_data.keys()
    assert not missing_keys, f"Dashboard response missing keys: {missing_keys}"

    # Call /api/dashboard without Authorization header
    try:
        dashboard_noauth_resp = requests.get(DASHBOARD_ENDPOINT, timeout=30)
    except requests.RequestException as e:
        assert False, f"Unauthorized dashboard request failed: {e}"

    assert dashboard_noauth_resp.status_code == 401, (
        f"Expected HTTP 401 for unauthorized request, got {dashboard_noauth_resp.status_code}"
    )
    # Optionally check error message in response
    try:
        error_data = dashboard_noauth_resp.json()
        assert (
            "error" in error_data or "message" in error_data
        ), "Unauthorized response missing error message"
    except Exception:
        # If invalid JSON, ignore
        pass


test_tc004_get_api_dashboard_with_and_without_authorization()

import requests
from datetime import datetime
import sys

BASE_URL = "http://localhost:3001"
ADMIN_EMAIL = "admin@example.com"
ADMIN_PASSWORD = "admin123"
TIMEOUT = 30

def test_get_apisubscriptions_active_and_expired():
    session = requests.Session()
    token = None

    # Login to get JWT token
    login_payload = {"email": ADMIN_EMAIL, "password": ADMIN_PASSWORD}
    try:
        login_resp = session.post(
            f"{BASE_URL}/api/auth/login",
            json=login_payload,
            timeout=TIMEOUT
        )
        assert login_resp.status_code == 200, f"Login failed with status {login_resp.status_code}, body: {login_resp.text}"
        token = login_resp.json().get("token")
        assert token and isinstance(token, str), "No token in login response"
    except Exception as e:
        sys.exit(f"Authentication failed: {e}")

    headers = {"Authorization": f"Bearer {token}"}

    # Get the subscriptions list
    try:
        resp = session.get(f"{BASE_URL}/api/subscriptions", headers=headers, timeout=TIMEOUT)
        assert resp.status_code == 200, f"Expected 200 OK, got {resp.status_code}, body: {resp.text}"
        obj = resp.json()

        # Adjusted: Check if response is a list or dict containing subscriptions list
        if isinstance(obj, list):
            subscriptions = obj
        elif isinstance(obj, dict):
            # Try common keys for list of subscriptions
            if "subscriptions" in obj and isinstance(obj["subscriptions"], list):
                subscriptions = obj["subscriptions"]
            elif "data" in obj and isinstance(obj["data"], list):
                subscriptions = obj["data"]
            else:
                assert False, f"Subscriptions list not found in response: {obj}"
        else:
            assert False, f"Invalid subscriptions response type: {type(obj)}"

        assert isinstance(subscriptions, list), "Subscriptions response is not a list"

        # Validate each subscription has correct status and startDate (and optionally expiry)
        now = datetime.utcnow()
        for sub in subscriptions:
            # Required fields: status and dates
            assert "status" in sub, f"Subscription missing 'status': {sub}"
            assert isinstance(sub["status"], str), f"Invalid status type: {sub}"

            assert "startDate" in sub, f"Subscription missing 'startDate': {sub}"
            assert sub["startDate"] is not None, f"Subscription 'startDate' is None: {sub}"

            # Validate date format ISO 8601 and parse
            try:
                start_date = datetime.fromisoformat(sub["startDate"].replace("Z", "+00:00"))
            except Exception:
                assert False, f"Invalid startDate format: {sub['startDate']}"

            # Optional expiryDate, if present validate format
            expiry_date = None
            if "expiryDate" in sub and sub["expiryDate"] is not None:
                try:
                    expiry_date = datetime.fromisoformat(sub["expiryDate"].replace("Z", "+00:00"))
                except Exception:
                    assert False, f"Invalid expiryDate format: {sub['expiryDate']}"

            # Status logic checks: if expiryDate passed, status should be expired or similar
            status_lower = sub["status"].lower()
            if expiry_date:
                if expiry_date < now:
                    # Expired subscriptions must have an expired or inactive status
                    assert "expir" in status_lower or "inactiv" in status_lower or "cancel" in status_lower or "disabled" in status_lower, (
                        f"Subscription expired but status not indicating expired: {sub}"
                    )
                else:
                    # Active subscriptions should have active status
                    assert "activ" in status_lower or "valid" in status_lower or "enabled" in status_lower, (
                        f"Subscription active but status not indicating active: {sub}"
                    )
            else:
                # If no expiryDate, status should be active or unknown state could fail this
                assert "activ" in status_lower or "valid" in status_lower or "enabl" in status_lower or "pend" in status_lower, (
                    f"Subscription with no expiryDate has unexpected status: {sub}"
                )

    finally:
        session.close()

test_get_apisubscriptions_active_and_expired()

import requests
import json

BASE_URL = "http://localhost:3001"
ADMIN_EMAIL = "admin@example.com"
ADMIN_PASSWORD = "admin123"
TIMEOUT = 30

def get_auth_token():
    try:
        response = requests.post(
            f"{BASE_URL}/api/auth/login",
            json={"email": ADMIN_EMAIL, "password": ADMIN_PASSWORD},
            timeout=TIMEOUT
        )
        response.raise_for_status()
        data = response.json()
        token = data.get("token")
        assert token, "No token in login response"
        return token
    except requests.RequestException as e:
        raise AssertionError(f"Authentication failed: {e}")
    except (ValueError, AssertionError) as e:
        raise AssertionError(f"Authentication response invalid: {e}")

def get_clients(auth_token):
    headers = {"Authorization": f"Bearer {auth_token}"}
    try:
        response = requests.get(f"{BASE_URL}/api/clients", headers=headers, timeout=TIMEOUT)
        response.raise_for_status()
        clients = response.json()
        assert isinstance(clients, list), "Clients response is not a list"
        return clients
    except requests.RequestException as e:
        raise AssertionError(f"Failed to get clients: {e}")
    except (ValueError, AssertionError) as e:
        raise AssertionError(f"Invalid clients response: {e}")

def test_post_apismsbulk_send_messages_to_clients():
    auth_token = get_auth_token()
    headers = {
        "Authorization": f"Bearer {auth_token}",
        "Content-Type": "application/json"
    }

    clients = get_clients(auth_token)
    if not clients:
        raise AssertionError("No clients available to send messages to")

    client_ids = [client.get("id") for client in clients if client.get("id") is not None]
    assert client_ids, "No valid client IDs found"

    payload = {
        "clientIds": client_ids,
        "message": "Test message from automated test"
    }

    try:
        response = requests.post(
            f"{BASE_URL}/api/sms/bulk",
            headers=headers,
            json=payload,
            timeout=TIMEOUT
        )
        assert response.status_code in (200, 201), f"Expected 200 OK or 201 Created, got {response.status_code}"
        resp_json = response.json()
        # Assuming response includes a success field or similar confirmation
        assert resp_json.get("success") is True or resp_json.get("status") == "success", \
            "Bulk SMS response does not indicate success"
    except requests.RequestException as e:
        raise AssertionError(f"Request failed: {e}")
    except (ValueError, AssertionError) as e:
        raise AssertionError(f"Response validation failed: {e}")

test_post_apismsbulk_send_messages_to_clients()
